    int l = 0, r = 0, max_len = 0, cur_len = 0;
    HashMap<Character, Integer> char_count = new HashMap<>();

    while (r < s.length()) {
        char_count.put(s.charAt(r), char_count.getOrDefault(s.charAt(r), 0) + 1);
        if (char_count.size() <= 2) {
            cur_len++;
        } else {
